89	// writeEventsAttachment writes the given events to the bead's sidecar file
90	// atomically (temp + rename) and creates the parent directory. An empty
91	// slice removes the sidecar.
92	func (s *Store) writeEventsAttachment(beadID string, events []BeadEvent) error {
93		dir := s.attachmentDir(beadID)
