1336	// Reopen sets a bead's status back to open, clears claim fields, optionally
1337	// appends notes, and records an immutable reopen event — all in one atomic
1338	// lock acquisition.
1339	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1340		now := time.Now().UTC()
1341		return s.WithLock(func() error {
1342			beads, _, err := s.readAllLatestRaw()
1343			if err != nil {
1344				return err
1345			}
1346			found := false
1347			for i := range beads {
1348				if beads[i].ID != id {
1349					continue
1350				}
1351				b := &beads[i]
1352				if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
1353					ManualReopen: true,
1354				}); err != nil {
1355					return err
1356				}
1357				b.Owner = ""
1358				b.UpdatedAt = now
1359				if b.Extra == nil {
1360					b.Extra = make(map[string]any)
1361				}
1362				// Clear claim fields
1363				for _, k := range ClaimMetadataExtraKeys {
1364					delete(b.Extra, k)
1365				}
1366				delete(b.Extra, ClaimHeartbeatExtraKey)
1367				// Append notes
1368				if appendNotes != "" {
1369					if b.Notes != "" {
1370						b.Notes = b.Notes + "\n\n" + appendNotes
1371					} else {
1372						b.Notes = appendNotes
1373					}
1374				}
1375				// Record reopen event. If events were externalized at close,
1376				// pull them back inline so the active row carries the full
1377				// history again and the attachment ref is dropped.
1378				if hasEventsAttachment(b) {
1379					if err := s.inlineEventsInPlace(b); err != nil {
1380						return err
1381					}
1382					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1383				}
1384				var events []BeadEvent
1385				if raw, ok := b.Extra["events"]; ok {
1386					events = decodeBeadEvents(raw)
1387				}
1388				evt := BeadEvent{
1389					Kind:      "reopen",
1390					CreatedAt: now,
1391				}
1392				if reason != "" {
1393					evt.Summary = reason
1394				}
1395				events = append(events, evt)
1396				encoded := make([]map[string]any, 0, len(events))
1397				for _, e := range events {
1398					encoded = append(encoded, map[string]any{
1399						"kind":       e.Kind,

1400						"summary":    e.Summary,
1401						"body":       e.Body,
1402						"actor":      e.Actor,
1403						"created_at": e.CreatedAt,
1404						"source":     e.Source,
1405					})
1406				}
1407				b.Extra["events"] = encoded
1408				if err := s.validateBead(b); err != nil {
1409					return err
1410				}
1411				if err := s.runHook("validate-bead-update", b); err != nil {
1412					return err
1413				}
1414				found = true
1415				break
1416			}
1417			if !found {
1418				return fmt.Errorf("bead: not found: %s", id)
1419			}
1420			if err := s.WriteAll(beads); err != nil {
1421				return err
1422			}
1423			return s.RemoveClaimHeartbeat(id)
1424		})
1425	}
