1492	type lifecycleQueueEntry struct {
1493		Bead
1494		Decision             LifecycleQueueDecision
1495		UnclosedDepIDs       []string
1496		RetryAfter           time.Time
1497		LastStatus           string
1498		LastDetail           string
1499		ExecutionSkipReason  string
1500		SupersededBy         string
1501		EpicClosureCandidate bool
1502	}
1503	
1504	func (s *Store) classifyLifecycleQueue(beads []Bead, now time.Time) []lifecycleQueueEntry {
1505		statusMap := make(map[string]string)
1506		childCount := make(map[string]int)
1507		openChildCount := make(map[string]int)
1508		for _, b := range beads {
1509			statusMap[b.ID] = b.Status
1510			if b.Parent != "" {
1511				childCount[b.Parent]++
1512				if b.Status != StatusClosed {
1513					openChildCount[b.Parent]++
1514				}
1515			}
1516		}
1517	
1518		// Read origin HEAD once per pass for rev-bound cooldown auto-invalidation.
1519		originHead := originMainHead(s.workingDir())
1520	
1521		entries := make([]lifecycleQueueEntry, 0, len(beads))
1522		for _, b := range beads {
1523			unclosed := unclosedDependencyIDs(b, statusMap)
1524			retryAfter, retryActive := activeRetryCooldown(b, now, originHead)
1525			executionEligible, executionEligibleKnown := lifecycleExecutionEligible(b)
1526			supersededBy := lifecycleSupersededBy(b)
1527			entry := lifecycleQueueEntry{
1528				Bead:                 b,
1529				UnclosedDepIDs:       unclosed,
1530				RetryAfter:           retryAfter,
1531				LastStatus:           extraStringVal(b.Extra, ExtraLastStatus),
1532				LastDetail:           extraStringVal(b.Extra, ExtraLastDetail),
1533				ExecutionSkipReason:  extraStringVal(b.Extra, ExtraExecutionReason),
1534				SupersededBy:         supersededBy,
1535				EpicClosureCandidate: isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]),
1536			}
1537			entry.Decision = EvaluateLifecycleQueue(LifecycleQueueFacts{
1538				Status:                 b.Status,
1539				Dependencies:           lifecycleDependencyStates(b, statusMap),
1540				ClaimFresh:             b.Status == StatusInProgress && !claimLeaseIsStale(s, b.Extra, b.ID),
1541				RetryCooldownActive:    retryActive,
1542				ExecutionEligible:      executionEligible,
1543				ExecutionEligibleKnown: executionEligibleKnown,
1544				SupersededBy:           supersededBy,
1545				EpicContainer:          isOrdinaryEpicContainer(b, childCount[b.ID]),
1546				ExternalBlockerReason:  extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
1547				LegacyLabels:           b.Labels,
1548			})
1549			entries = append(entries, entry)
1550		}
1551		return entries
1552	}
