1554	func lifecycleDependencyStates(b Bead, statusMap map[string]string) []LifecycleDependencyState {
1555		depIDs := b.DepIDs()
1556		if len(depIDs) == 0 {
1557			return nil
1558		}
1559		deps := make([]LifecycleDependencyState, 0, len(depIDs))
1560		for _, depID := range depIDs {
1561			deps = append(deps, LifecycleDependencyState{Status: statusMap[depID]})
1562		}
1563		return deps
1564	}
