1566	func unclosedDependencyIDs(b Bead, statusMap map[string]string) []string {
1567		var unclosed []string
1568		for _, depID := range b.DepIDs() {
1569			if !LifecycleStatusSatisfiesDependency(statusMap[depID]) {
1570				unclosed = append(unclosed, depID)
1571			}
