1654	// ReadyExecutionBreakdown is the lifecycle-derived queue snapshot used by the
1655	// worker when explaining an empty execution queue.
1656	type ReadyExecutionBreakdown struct {
1657		ExecutionReady            []string
1658		DependencyWaiting         []string
1659		ProposedOperatorAttention []string
1660		RetryCooldown             []string
1661		ExternalBlocked           []string
1662		NotEligible               []string
1663		Superseded                []string
1664		Epics                     []string
1665		EpicClosureCandidates     []string
1666		NextRetryAfter            string
1667		HumanReviewBlockedTotal   int
1668		HumanReviewBlockers       []HumanReviewBlockerPressure
