1671	// HumanReviewBlockerPressure describes an open human-review blocker and the
1672	// number of active downstream beads that transitively depend on it.
1673	type HumanReviewBlockerPressure struct {
1674		ID                     string
1675		Title                  string
1676		Priority               int
1677		DownstreamBlockedCount int
1678	}
1679	
1680	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1681		out := ReadyExecutionBreakdown{}
1682		beads, err := s.ReadAll()
1683		if err != nil {
1684			return out, err
1685		}
1686		now := time.Now().UTC()
1687		var soonestRetry time.Time
1688		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1689			switch entry.Decision.Bucket {
1690			case LifecycleBucketReady:
1691				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
1692			case LifecycleBucketWaitingDependencies:
1693				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
1694			case LifecycleBucketRetryCooldown:
1695				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
1696				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
1697					soonestRetry = entry.RetryAfter
1698				}
1699			case LifecycleBucketEpicContainer:
1700				if entry.EpicClosureCandidate {
1701					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
1702				} else {
1703					out.Epics = append(out.Epics, entry.ID)
1704				}
1705			case LifecycleBucketNotEligible:
1706				out.NotEligible = append(out.NotEligible, entry.ID)
1707			case LifecycleBucketSuperseded:
1708				out.Superseded = append(out.Superseded, entry.ID)
1709			case LifecycleBucketBlockedExternal:
1710				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
1711			case LifecycleBucketProposed:
1712				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
1713			}
1714		}
1715		if !soonestRetry.IsZero() {
1716			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1717		}
1718		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
1719		return out, nil
1720	}
1721	
1722	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
1723		byID := make(map[string]Bead, len(beads))
1724		reverseDeps := make(map[string][]string, len(beads))
1725		for _, b := range beads {
1726			byID[b.ID] = b
1727			if !activeForDependencyPressure(b) {
1728				continue
1729			}
1730			for _, dep := range b.Dependencies {
1731				if dep.DependsOnID == "" {
1732					continue
1733				}
1734				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
1735			}
1736		}
1737	
1738		var blockers []HumanReviewBlockerPressure
1739		totalBlocked := map[string]struct{}{}
1740		for _, b := range beads {
1741			if !isHumanReviewBlocker(b) {
1742				continue
1743			}
1744			seen := map[string]struct{}{}
1745			var walk func(string)
1746			walk = func(id string) {
1747				for _, childID := range reverseDeps[id] {
1748					if childID == b.ID {
1749						continue
1750					}
1751					child, ok := byID[childID]
1752					if !ok || !activeForDependencyPressure(child) {
1753						continue
1754					}
1755					if _, exists := seen[childID]; exists {
1756						continue
1757					}
1758					seen[childID] = struct{}{}
1759					totalBlocked[childID] = struct{}{}
1760					walk(childID)
1761				}
1762			}
1763			walk(b.ID)
1764			if len(seen) == 0 {
1765				// A proposed/needs-human bead with no active downstream is operator
1766				// attention only; it does not contribute to HumanReviewBlockers.
1767				continue
1768			}
1769			blockers = append(blockers, HumanReviewBlockerPressure{
1770				ID:                     b.ID,
1771				Title:                  b.Title,
1772				Priority:               b.Priority,
1773				DownstreamBlockedCount: len(seen),
1774			})
1775		}
1776	
1777		sort.SliceStable(blockers, func(i, j int) bool {
1778			if blockers[i].Priority != blockers[j].Priority {
1779				return blockers[i].Priority < blockers[j].Priority
1780			}
1781			return blockers[i].ID < blockers[j].ID
1782		})
1783		return blockers, len(totalBlocked)
1784	}
1785	
1786	func isHumanReviewBlocker(b Bead) bool {
1787		// Post-lifecycle: proposed status is the canonical operator-attention signal.
1788		if b.Status == StatusProposed {
1789			return true
1790		}
1791		// Legacy: open beads with investigation/human-review labels still count.
1792		if b.Status != StatusOpen {
1793			return false
1794		}
1795		for _, label := range b.Labels {
1796			switch label {
1797			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
1798				return true
1799			}

