218	func analyzeExtractDim(r attemptmetrics.AttemptRow, dim string) string {
219		switch dim {
220		case "model":
221			return r.Model
222		case "harness":
223			return r.Harness
224		case "profile":
225			return r.Profile
226		case "prompt_template_hash":
227			return r.PromptTemplateHash
228		case "spec_id":
229			return r.SpecID
230		case "outcome":
231			return r.Outcome
232		case "bead_id":
233			return r.BeadID
234		case "day":
235			if r.TSStart == "" {
236				return ""
237			}
238			t, err := time.Parse(time.RFC3339, r.TSStart)
239			if err != nil {
240				return ""
241			}
242			return t.UTC().Format("2006-01-02")
243		case "week":
244			if r.TSStart == "" {
245				return ""
246			}
247			t, err := time.Parse(time.RFC3339, r.TSStart)
248			if err != nil {
249				return ""
250			}
251			y, w := t.UTC().ISOWeek()
252			return fmt.Sprintf("%04d-W%02d", y, w)
253		case "month":
254			if r.TSStart == "" {
255				return ""
256			}
257			t, err := time.Parse(time.RFC3339, r.TSStart)
258			if err != nil {
259				return ""
260			}
261			return t.UTC().Format("2006-01")
262		}
263		return ""
264	}
