1259	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1260	// sessionID is the agent session that completed the work.
1261	// commitSHA is the exact closing commit SHA when it is known.
1262	//
1263	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1264	// via this path without a terminal verdict event plus execution evidence.
1265	// Store.Close is the manual-administration escape hatch when the gate is
1266	// inappropriate.
1267	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1268		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1269			return err
1270		}
1271		// Externalize events only when the gate actually transitioned the bead
1272		// to closed; rejected closes leave the bead open and inline.
1273		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1274			if err := s.externalizeEvents(id); err != nil {
1275				return err
1276			}
1277		}
1278		_ = s.RemoveClaimHeartbeat(id)
1279		s.maybeOpportunisticMaintenance()
1280		return nil
1281	}
