1284		return s.updateBead(id, true, func(b *Bead) error {
1285			if b.Extra == nil {
1286				b.Extra = make(map[string]any)
1287			}
1288			if sessionID != "" {
1289				b.Extra["session_id"] = sessionID
1290			}
1291			if commitSHA != "" {
1292				b.Extra["closing_commit_sha"] = commitSHA
1293			}
1294			// ClosureGate guards the evidence-close path only; reconcile-close skips
1295			// it by design (TD-031 §5).
1296			if err := ClosureGate(b); err != nil {
1297				// Surface via bead notes so a later operator audit can see why the
1298				// close was refused; a single error path would be dropped by the
1299				// Update callback signature (no error return).
1300				appendClosureRejectNote(b, err)
1301				return nil
1302			}
1303			return transitionLifecycleInPlace(b, StatusClosed, LifecycleTransitionOptions{
1304				ManualClose: true,
1305				Reason:      "close with evidence",
1306				Source:      "Store.CloseWithEvidence",
1307			})
1308		})
1309	}
