1311	func appendClosureRejectNote(b *Bead, err error) {
1312		stamp := time.Now().UTC().Format(time.RFC3339)
1313		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1314		if b.Notes == "" {
1315			b.Notes = note
1316			return
1317		}
1318		b.Notes = b.Notes + "\n" + note
1319	}
