1427	// List returns beads matching optional filters.
1428	// where is an optional map of key=value predicates that match against
1429	// known struct fields and Extra (unknown/workflow-specific) fields.
1430	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1431		beads, err := s.ReadAll()
1432		if err != nil {
1433			return nil, err
1434		}
1435		var result []Bead
1436		for _, b := range beads {
1437			if status != "" && b.Status != status {
1438				continue
1439			}
1440			if label != "" && !containsString(b.Labels, label) {
1441				continue
1442			}
1443			if !matchesWhere(b, where) {
1444				continue
1445			}
1446			result = append(result, b)
1447		}
1448		return result, nil
1449	}
