1451	// matchesWhere returns true if the bead satisfies all key=value predicates.
1452	// It checks known struct fields first, then falls back to Extra.
1453	func matchesWhere(b Bead, where map[string]string) bool {
1454		for k, v := range where {
1455			var actual string
1456			switch k {
1457			case "id":
1458				actual = b.ID
1459			case "title":
1460				actual = b.Title
1461			case "status":
1462				actual = b.Status
1463			case "issue_type":
1464				actual = b.IssueType
1465			case "owner":
1466				actual = b.Owner
1467			case "assignee":
1468				actual = b.Owner
1469			case "parent":
1470				actual = b.Parent
1471			case "description":
1472				actual = b.Description
1473			case "acceptance":
1474				actual = b.Acceptance
1475			case "notes":
1476				actual = b.Notes
1477			default:
1478				// Fall back to Extra map for unknown/workflow-specific fields
1479				if b.Extra != nil {
1480					if ev, ok := b.Extra[k]; ok {
1481						actual = fmt.Sprintf("%v", ev)
1482					}
1483				}
1484			}
1485			if actual != v {
1486				return false
1487			}
1488		}
1489		return true
1490	}
