336	func analyzeWriteCSV(w io.Writer, dims []string, rows []analyzeResultRow) error {
337		cw := csv.NewWriter(w)
338		headers := make([]string, 0, len(dims)+len(analyzeAggHeaders))
339		headers = append(headers, dims...)
340		headers = append(headers, analyzeAggHeaders...)
341		if err := cw.Write(headers); err != nil {
342			return err
343		}
344		for _, r := range rows {
345			row := make([]string, 0, len(headers))
346			for _, d := range dims {
347				row = append(row, r.Dimensions[d])
348			}
349			row = append(row, analyzeAggValues(r)...)
350			if err := cw.Write(row); err != nil {
351				return err
352			}
353		}
354		cw.Flush()
355		return cw.Error()
356	}
357	
358	func analyzeWriteTable(w io.Writer, dims []string, rows []analyzeResultRow) error {
359		tw := tabwriter.NewWriter(w, 0, 0, 2, ' ', 0)
360		headers := make([]string, 0, len(dims)+len(analyzeAggHeaders))
361		headers = append(headers, dims...)
362		headers = append(headers, analyzeAggHeaders...)
363		_, _ = fmt.Fprintln(tw, strings.Join(headers, "\t"))
364		for _, r := range rows {
365			vals := make([]string, 0, len(headers))
366			for _, d := range dims {
367				v := r.Dimensions[d]
368				if v == "" {
369					v = "(none)"
370				}
371				vals = append(vals, v)
372			}
373			vals = append(vals, analyzeAggValues(r)...)
374			_, _ = fmt.Fprintln(tw, strings.Join(vals, "\t"))
375		}
376		return tw.Flush()
377	}
