1891	func formatAttemptRouteEconomics(attempt agent.ExecuteBeadReport) string {
1892		if attempt.Harness == "" && attempt.Provider == "" && attempt.Model == "" {
1893			return ""
1894		}
1895		parts := []string{}
1896		if attempt.Harness != "" {
1897			parts = append(parts, "harness="+attempt.Harness)
1898		}
1899		if attempt.Provider != "" {
1900			parts = append(parts, "provider="+attempt.Provider)
1901		}
1902		if attempt.Model != "" {
1903			parts = append(parts, "model="+attempt.Model)
1904		}
1905		power := attempt.PredictedPower
1906		if power == 0 {
1907			power = attempt.ActualPower
1908		}
1909		if power > 0 {
1910			parts = append(parts, fmt.Sprintf("power=%d", power))
1911		}
1912		if attempt.PredictedSpeedTPS > 0 {
1913			parts = append(parts, fmt.Sprintf("speed=%.1f tok/s", attempt.PredictedSpeedTPS))
1914		}
1915		if attempt.PredictedCostUSDPer1kTokens > 0 {
1916			cost := fmt.Sprintf("cost=$%.6f/1k tok", attempt.PredictedCostUSDPer1kTokens)
1917			if attempt.PredictedCostSource != "" {
1918				cost += " source=" + attempt.PredictedCostSource
1919			}

