24	// runAnalyze creates and executes the analyze command with the given args,
25	// returning stdout+stderr output.
26	func runAnalyze(t *testing.T, dir string, args ...string) string {
27		t.Helper()
28		var out bytes.Buffer
29		f := &CommandFactory{WorkingDir: dir}
30		cmd := f.newWorkAnalyzeCommand()
31		cmd.SetOut(&out)
32		cmd.SetErr(&out)
33		cmd.SetArgs(append(args, "--project", dir))
34		if err := cmd.Execute(); err != nil {
35			t.Fatalf("analyze command failed: %v\noutput: %s", err, out.String())
36		}
37		return out.String()
38	}
